def makeLargestSpecial(s):
    count = i = 0
    subs = []
    for j, c in enumerate(s):
        if c == '1': count += 1
        else: count -= 1
        if count == 0:
            subs.append('1' + makeLargestSpecial(s[i+1:j]) + '0')
            i = j + 1
    return ''.join(sorted(subs, reverse=True))

